text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스 진행"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "불일치 발생 시 먼저 패키지 설정(구성) 점검, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표이며 확정 공개 릴리스 결정이 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "note": "가능하면 목요일까지 검토 제안만 있었고 담당자 미지정"
      }
    ],
    "risks": [
      "tarball 경로 오류 시 릴리스 지연 위험",
      "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자 오해를 유발할 위험"
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 확인",
      "due": "미정",
      "status": "대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 절차 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "제안",
      "source_certainty": "suggested_unassigned"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 스모크 테스트 결과 수신 여부 확인",
      "금요일 12:00 KST action_items.md 실패 트리아지 노트 작성 여부 확인",
      "스모크 결과 이후 tarball 경로 검증 완료 여부 확인",
      "README 설치 절차 검토 담당자 지정 필요 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 스트레치 목표 언급 여부 결정"
    ],
    "do_not_invent": [
      "고객명/외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 owner를 임의 지정",
      "명시되지 않은 마감시각"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객/예산/보안/장애/법무 사실을 추가하지 않는다.",
    "확정 결정과 제안/미결 항목을 분리해 기록한다.",
    "반려된 제안은 실행 항목으로 승격하지 않는다.",
    "담당자·마감이 없는 항목은 '미지정' 또는 '미정'으로 표시한다.",
    "내부 스트레치 목표를 확정 공개 일정으로 오인하지 않는다."
  ]
}
